65			const record = data[i];
66	
67			if (schemaName === "merchGroup") {
68				try {
69					const modTime = new Date(record.modTime);
70					if (isNaN(modTime)) throw new Error("Invalid modTime format");
71	
72					// Step 1: Find existing record by composite keys
73					const existing = await sql[schemaName].findOne({
74						where: {
75							mgTypeCode: record.mgTypeCode,
76							mg_desc: {
77								[Op.iLike]: record.mg_desc
78							},
79							mg_code: record.mg_code,
80							ItemNoCode: record.ItemNoCode,
81							divisionCode_fk: record.divisionCode_fk,
82							companyCode_fk: record.companyCode_fk,
83						},
84					});
85	
86					if (!existing) {
87						// Step 2: Insert if not found
88						const created = await sql[schemaName].create(record);
89						newItems.push(created);
90						console.log(`🆕 New item created: ${created.mgTypeCode} : ${created.mg_desc}`);
91					} else {
92						// Step 3: Update only if incoming data is newer
93						const existingModTime = new Date(existing.modTime);
94						if (modTime > existingModTime) {
95							// Extract dynamically and filter the allowed fields whitelist (excludes mgCategory and audit fields)
96							const allowedFields = Object.keys(record).filter(key =>
